// src/components/WelcomeScreen.jsx
import React, { useState } from 'react';
import VoiceButton from './VoiceButton';
import SuggestionOverlay from './SuggestionOverlay';
import { useTranslation } from '../context/TranslationContext';

export default function WelcomeScreen() {
  const { languageData } = useTranslation();
  const [showOverlay, setShowOverlay] = useState(false);

  const handleVoiceClick = () => {
    setShowOverlay((prev) => !prev);
  };

  return (
    <section className="screen-welcome kiosk-screen active">
      <div className="welcome-logo">
        <div className="welcome-logo-icon">🚀</div>
      </div>
      <h1 className="welcome-title">
        {languageData?.welcomeTitle || 'Welcome'}
      </h1>
      <p className="welcome-subtitle">
        {languageData?.welcomeSubtitle || 'Select a service or speak for assistance.'}
      </p>
      <div className="welcome-interaction-panel">
        <VoiceButton onClick={handleVoiceClick} />
        {showOverlay && <SuggestionOverlay onClose={() => setShowOverlay(false)} />}
      </div>
    </section>
  );
}
